mapper.select:
select province, sum(quantity) as sum from o_order
where status = #{status}

    and brand = #{brand}


    and order_type = #{orderType}


    and create_time >= #{createTimeStart}

GROUP BY province

SELECT
    o.province,
    sum(o.quantity) AS sum
FROM
    o_order o
    JOIN o_hanging_order oho ON oho.order_id = o.order_code AND oho.status = 1
WHERE
    o.`status` = #{status}
    AND oho.last_compete_company = #{companyId}
    AND oho.create_time >  #{createTime}

    and brand = #{brand}

GROUP BY
    o.province

SELECT
    o.brand,
    sum(o.quantity) AS sum
FROM
    o_order o
    JOIN o_hanging_order oho ON oho.order_id = o.order_code AND oho.status = 1
WHERE
    o.`status` = #{status}
    AND oho.last_compete_company = #{companyId}
    AND oho.create_time >  #{createTime}

    and o.province= #{province}

GROUP BY
    o.brand

select brand, sum(quantity) as sum from o_order where status = #{status}

    and province = #{province}


    and create_time >= #{createTimeStart}


    and create_time >= #{createTimeStart}


    and order_type = #{orderType}

GROUP BY brand

SELECT o.order_code, o.erp_order_id, o.status, oto.trade_company_name tradeCompanyName, oto.trade_user_name, oto.create_time, o.send_time, o.shipments_time, o.signed_time, o.brand, o.category, o.product_name, o.sku_name, o.quantity, oto.quantity warehouseQuantity, o.sub_status, o.province, o.city, o.addressee, o.phone, o.receiving_address, o.handle_apply, oto.trade_price, oto.accounting_period, oto.tracking_number, oto.tracking_company, oto.create_time lastCompeteTime , oto.trade_user_name, oto.trade_user_phone, o.order_style, oto.delivery_code, o.remark, o.payer_name payerName FROM o_order o INNER JOIN o_trade_order oto ON o.order_code = oto.order_id AND oto.`status` = 2
and o.order_type = #{orderType}
and oto.delivery_code = #{deliveryCode}
and oto.trade_company_id = #{companyId}
#{status}
#{orderCode}
and o.create_time > #{createTime}
and o.province = #{province}
and o.order_code = #{orderCode}
and o.brand like concat('%',#{brand},'%')
and o.category like concat('%',#{category},'%')
and o.product_name like concat('%',#{productName},'%')
and o.sku_name like concat('%',#{skuName},'%')
and o.shipments_time>= #{sendStartTime}
and o.shipments_time <= #{sendStartTime}
and o.signed_time>= #{signedStartTime}
and o.signed_time <= #{signedEndTime}
order by oto.create_time desc

SELECT
    province,
    city,
    count(*) AS count
FROM
    o_order
WHERE
brand = #{brand} and create_time >= #{gtCreateDateTime}

    #{category}


    #{status}


   and address_status = #{addressStatus}


    and product_name = #{productName}


    and sku_name = #{skuName}

GROUP BY
    province,
    city

SELECT
    product_name,
    count(*) AS quantity
FROM
    o_order
WHERE
    brand = #{brand} and create_time >= #{gtCreateDateTime}

    and address_status = #{addressStatus}


    and province = #{province}


    and city = #{city}


    and product_name like concat('%',#{productName},'%')


    #{category}


    #{status}

GROUP BY
    product_name
order by quantity

SELECT
    sku_name,
    count(*) AS quantity
FROM
    o_order
WHERE
    brand = #{brand} and create_time >= #{gtCreateDateTime}

    and address_status = #{addressStatus}


    and province = #{province}


    and city = #{city}


    and product_name = #{productName}


    #{category}


    #{status}

GROUP BY
    sku_name

SELECT o.order_code, o.erp_order_id, o.original_order_id,
o.brand, o.category, o.platform, o.shop_name, o.product_name, o.sku_name, o.quantity,
o.sub_status, oto.trade_company_name tradeCompanyName, oto.trade_user_name, oto.trade_user_phone,
oto.create_time, o.send_time, o.last_shipping_time, o.shipments_time, o.signed_time, oto.create_time lastCompeteTime ,
o.province, o.city,
o.addressee, o.phone, o.receiving_address,
o.handle_apply, oho.delivery_time, oho.price_highest, oho.price_highest_status, oho.price_hign, oho.price_hign_status, oho.price_low, oho.price_low_status, oho.price_lowest, oho.price_lowest_status,
oto.trade_price, oto.accounting_period, oto.tracking_number, oto.tracking_company, oto.trade_nick_name,
o.order_style, oto.tracking_number, oto.tracking_company
FROM o_order o INNER JOIN o_hanging_order oho ON o.order_code = oho.order_id and oho.status = 1 INNER JOIN o_trade_order oto ON o.order_code = oto.order_id AND oto.`status` = 2
and o.order_type = #{orderType}
and oto.delivery_code = #{deliveryCode}
and oto.trade_company_id = #{companyId}
and o.status = #{status}
and o.original_order_id = #{originalOrderId}
#{status}
#{orderCode}
#{originalOrderId}
and o.create_time > #{createTimeStart}
and o.province = #{province}
and o.order_code = #{orderCode}
and o.brand like concat('%',#{brand},'%')
and o.category like concat('%',#{category},'%')
and o.product_name like concat('%',#{productNameLike},'%')
and o.sku_name like concat('%',#{skuNameLike},'%')
and o.shipments_time>= #{sendStartTime}
and o.shipments_time <= #{sendStartTime}
and o.signed_time>= #{signedStartTime}
and o.signed_time <= #{signedEndTime}
order by o.${sort}
